          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let S = Unifi_SiteManager_Sites_CL\n    | where \"value::all\" in~ ({SiteFilter}) or tostring(SiteId) in~ ({SiteFilter})\n    | summarize arg_max(TimeGenerated, *) by tostring(SiteId);\nlet SelectedHostIds = toscalar(S | summarize make_set(HostId));\nlet H = Unifi_SiteManager_Hosts_CL | where \"value::all\" in~ ({SiteFilter}) or Id in (SelectedHostIds) | summarize arg_max(TimeGenerated, *) by Id;\nlet D = Unifi_SiteManager_Devices_CL | summarize arg_max(TimeGenerated, *) by Id;\nlet I = SecurityIncident | where TimeGenerated > ago(7d) | where Title startswith \"UniFi Site Manager\" | summarize arg_max(LastModifiedTime, *) by IncidentNumber | where Status != \"Closed\";\nunion\n  (S | summarize V=toreal(count())                                                              | extend Metric=\"Sites\",                Order=1),\n  (H | summarize V=toreal(count())                                                              | extend Metric=\"Hosts\",                Order=2),\n  (D | summarize V=toreal(count())                                                              | extend Metric=\"Devices (estate)\",     Order=3),\n  (D | where Status =~ \"online\"                                                                 | summarize V=toreal(count()) | extend Metric=\"Online\",                Order=4),\n  (D | where Status =~ \"offline\"                                                                | summarize V=toreal(count()) | extend Metric=\"Offline\",               Order=5),\n  (D | where FirmwareStatus in~ (\"UpdateAvailable\",\"updatePending\")                             | summarize V=toreal(count()) | extend Metric=\"Need firmware update\", Order=6),\n  (S | extend WanUptime=todouble(SiteStatistics.percentages.wanUptime)                          | summarize V=todouble(round(avg(WanUptime),1)) | extend Metric=\"Avg WAN uptime %\", Order=7),\n  (I | summarize V=toreal(count())                                                              | extend Metric=\"Open incidents\",       Order=8)\n| order by Order asc | project Metric, Value=V",
              "size": 3,
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
