            "content": {
              "json": "<div style=\"border-left:4px solid #3b82f6;padding:6px 12px;margin:8px 0 0 0;background:rgba(59,130,246,0.05);font-size:14px;font-weight:600;letter-spacing:0.3px;text-transform:uppercase;color:#94a3b8\">Top sites by issues</div>"
