          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let _siteNames = Unifi_SiteManager_Sites_CL\n    | summarize arg_max(TimeGenerated, *) by tostring(SiteId)\n    | where isnotempty(SiteId)\n    | join kind=leftouter (\n        Unifi_SiteManager_Hosts_CL\n        | summarize arg_max(TimeGenerated, *) by Id\n        | project HostId = Id, FriendlyName = tostring(ReportedState.name)\n      ) on HostId\n    | extend MetaName = tostring(Meta.name), Suffix = substring(tostring(SiteId), 0, 6)\n    | project SiteId = tostring(SiteId),\n              SiteName = coalesce(\n                  iif(isnotempty(FriendlyName), FriendlyName, \"\"),\n                  iif(MetaName != \"default\" and isnotempty(MetaName), MetaName, \"\"),\n                  strcat(MetaName, \" (\", Suffix, \")\"));\nUnifi_SiteManager_Sites_CL\n| where TimeGenerated > ago(2h)\n| where \"value::all\" in~ ({SiteFilter}) or tostring(SiteId) in~ ({SiteFilter})\n| summarize arg_max(TimeGenerated, *) by tostring(SiteId)\n| where isnotempty(SiteId)\n| project-away SiteName\n| extend SiteId=tostring(SiteId),\n         Total=toint(SiteStatistics.counts.totalDevice),\n         Offline=toint(SiteStatistics.counts.offlineDevice),\n         OfflineGW=toint(SiteStatistics.counts.offlineGatewayDevice),\n         PendingUpdates=toint(SiteStatistics.counts.pendingUpdateDevice),\n         CritNotifs=toint(SiteStatistics.counts.criticalNotification),\n         WanUptime=todouble(SiteStatistics.percentages.wanUptime),\n         TxRetry=todouble(SiteStatistics.percentages.txRetry)\n| join kind=leftouter _siteNames on SiteId\n| extend IssueScore = Offline*5 + OfflineGW*10 + PendingUpdates*1 + CritNotifs*3 + iif(WanUptime < 95, 5, 0)\n| where IssueScore > 0\n| project SiteName, IssueScore, Offline, OfflineGW, PendingUpdates, CritNotifs, WanUptime, TxRetry\n| order by IssueScore desc",
              "size": 0,
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "crossComponentResources": [
                "{Workspace}"
