            "content": {
              "version": "KqlItem/1.0",
              "query": "let S = Unifi_SiteManager_Sites_CL\n    | where \"value::all\" in~ ({SiteFilter}) or tostring(SiteId) in~ ({SiteFilter})\n    | summarize arg_max(TimeGenerated, *) by tostring(SiteId);\nunion\n  (S | summarize V=toreal(count())                                            | extend Metric=\"Total sites\",        Order=1),\n  (S | where IsOwner == true                                                  | summarize V=toreal(count()) | extend Metric=\"Owned\",              Order=2),\n  (S | extend U=todouble(SiteStatistics.percentages.wanUptime) | where U < 95 | summarize V=toreal(count()) | extend Metric=\"WAN uptime < 95%\",   Order=3),\n  (S | extend C=toint(SiteStatistics.counts.criticalNotification) | where C>0 | summarize V=toreal(count()) | extend Metric=\"Critical notifs\",    Order=4),\n  (S | extend O=toint(SiteStatistics.counts.offlineDevice) | where O > 0     | summarize V=toreal(count()) | extend Metric=\"Has offline devices\", Order=5),\n  (S | extend P=toint(SiteStatistics.counts.pendingUpdateDevice) | where P>0 | summarize V=toreal(count()) | extend Metric=\"Pending updates\",     Order=6),\n  (S | extend Insp=tostring(SiteStatistics.gateway.inspectionState) | where Insp != \"on\" | summarize V=toreal(count()) | extend Metric=\"DPI off / no inspect\", Order=7)\n| order by Order asc | project Metric, Value=V",
