              "query": "let _siteNames = Unifi_SiteManager_Sites_CL\n    | summarize arg_max(TimeGenerated, *) by tostring(SiteId)\n    | where isnotempty(SiteId)\n    | join kind=leftouter (\n        Unifi_SiteManager_Hosts_CL\n        | summarize arg_max(TimeGenerated, *) by Id\n        | project HostId = Id, FriendlyName = tostring(ReportedState.name)\n      ) on HostId\n    | extend MetaName = tostring(Meta.name), Suffix = substring(tostring(SiteId), 0, 6)\n    | project SiteId = tostring(SiteId),\n              SiteName = coalesce(\n                  iif(isnotempty(FriendlyName), FriendlyName, \"\"),\n                  iif(MetaName != \"default\" and isnotempty(MetaName), MetaName, \"\"),\n                  strcat(MetaName, \" (\", Suffix, \")\"));\nUnifi_SiteManager_Sites_CL\n| where \"value::all\" in~ ({SiteFilter}) or tostring(SiteId) in~ ({SiteFilter})\n| summarize arg_max(TimeGenerated, *) by tostring(SiteId)\n| extend SiteId=tostring(SiteId),\n         Wired=toint(SiteStatistics.counts.wiredClient),\n         WiFi=toint(SiteStatistics.counts.wifiClient),\n         Guest=toint(SiteStatistics.counts.guestClient),\n         Devices=toint(SiteStatistics.counts.totalDevice)\n| join kind=leftouter _siteNames on SiteId\n| project SiteName, Devices, Wired, WiFi, Guest",
