              "query": "Unifi_SiteManager_Sites_CL\n| where \"value::all\" in~ ({SiteFilter}) or tostring(SiteId) in~ ({SiteFilter})\n| summarize arg_max(TimeGenerated, *) by tostring(SiteId)\n| extend ISP=tostring(SiteStatistics.ispInfo.name),\n         Org=tostring(SiteStatistics.ispInfo.organization)\n| summarize Sites=count(), Orgs=make_set(Org) by ISP\n| order by Sites desc",
