        "items": [
          {
            "type": 1,
            "content": {
              "json": "<div style=\"border-left:4px solid #3b82f6;padding:6px 12px;margin:8px 0 0 0;background:rgba(59,130,246,0.05);font-size:14px;font-weight:600;letter-spacing:0.3px;text-transform:uppercase;color:#94a3b8\">Ingest rate per table (last 24h)</div>"
            },
            "name": "div-ingest-rate-per-tabl-68924a"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union withsource=Table Unifi_SiteManager_Sites_CL, Unifi_SiteManager_Hosts_CL, Unifi_SiteManager_Devices_CL, Unifi_SiteManager_ISPMetrics_CL\n| where TimeGenerated > ago(24h)\n| summarize Rows=count() by Table, bin(TimeGenerated, 1h)\n| order by TimeGenerated asc",
              "size": 0,
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "crossComponentResources": [
                "{Workspace}"
              ],
              "visualization": "timechart",
              "title": "Rows ingested per Site Manager table per hour (last 24h)",
              "noDataMessage": "No Site Manager data ingested in the last 24h - check the connector card under Sentinel > Data connectors.",
              "noDataMessageStyle": 5
            },
            "name": "q-67b70dda"
          },
          {
            "type": 1,
            "content": {
              "json": "<div style=\"border-left:4px solid #3b82f6;padding:6px 12px;margin:8px 0 0 0;background:rgba(59,130,246,0.05);font-size:14px;font-weight:600;letter-spacing:0.3px;text-transform:uppercase;color:#94a3b8\">Per-table freshness</div>"
            },
            "name": "div-per-table-freshness-ab964f"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union withsource=Table Unifi_SiteManager_Sites_CL, Unifi_SiteManager_Hosts_CL, Unifi_SiteManager_Devices_CL, Unifi_SiteManager_ISPMetrics_CL\n| summarize LastRow=max(TimeGenerated), TotalRows=count() by Table\n| extend MinutesAgo=toint((now() - LastRow) / 1m)\n| extend Status=case(MinutesAgo < 15, \"Fresh\", MinutesAgo < 60, \"Recent\", MinutesAgo < 360, \"Stale\", \"Very Stale\")\n| project Table, LastRow, MinutesAgo, TotalRows, Status\n| order by MinutesAgo asc",
              "size": 0,
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "crossComponentResources": [
                "{Workspace}"
              ],
              "visualization": "table",
              "title": "How current is each Site Manager table?",
              "gridSettings": {
                "formatters": [
